.sig-xianxia-hero {
  position: relative;
  width: min(100%, 980px);
  min-height: 440px;
  display: grid;
  grid-template-columns: minmax(0, 1.08fr) minmax(260px, 0.82fr);
  gap: 34px;
  align-items: stretch;
  padding: 42px;
  overflow: hidden;
  border: 1px solid rgba(218,191,124,0.30);
  border-radius: 16px;
  background: linear-gradient(145deg, rgba(16,29,25,0.88), rgba(218,191,124,0.10));
  color: #f3ead2;
  box-shadow: 0 32px 82px rgba(4,8,7,0.40);
  font-family: Inter, "Noto Sans SC", ui-sans-serif, system-ui, sans-serif;
}
.sig-xianxia-hero::before { content: ""; position: absolute; inset: 0; background: radial-gradient(circle at 50% 0%, rgba(218,191,124,0.22), transparent 30%), linear-gradient(90deg, rgba(143,199,170,0.10), transparent); background-size: auto; opacity: 0.78; pointer-events: none; }
.sig-xianxia-hero > * { position: relative; z-index: 1; }
.sig-xianxia-hero .copy { display: grid; align-content: center; gap: 18px; }
.sig-xianxia-hero .kicker { width: fit-content; border: 1px solid rgba(218,191,124,0.30); border-radius: 999px; padding: 6px 10px; color: #dabf7c; background: rgba(218,191,124,0.10); font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-xianxia-hero h1 { margin: 0; max-width: 620px; font-family: "Noto Serif SC", Georgia, serif; font-size: clamp(40px, 6.4vw, 70px); font-weight: 760; line-height: 0.98; letter-spacing: 0; }
.sig-xianxia-hero p { margin: 0; max-width: 560px; color: #b7c3aa; font-size: 15px; line-height: 1.78; }
.sig-xianxia-hero .actions { display: flex; flex-wrap: wrap; gap: 10px; padding-top: 6px; }
.sig-xianxia-hero button { height: 40px; padding: 0 16px; border-radius: calc(16px / 2 + 4px); border: 1px solid rgba(218,191,124,0.30); font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; transition: transform 180ms cubic-bezier(0.16, 1, 0.3, 1), border-color 180ms; }
.sig-xianxia-hero .primary { background: #dabf7c; color: #101d19; border-color: #dabf7c; }
.sig-xianxia-hero .secondary { background: transparent; color: #f3ead2; }
.sig-xianxia-hero button:hover { transform: translateY(-1px); border-color: #dabf7c; }
.sig-xianxia-hero .artifact { display: grid; align-content: space-between; gap: 18px; padding: 22px; border: 1px solid rgba(218,191,124,0.30); border-radius: calc(16px - 2px); background: rgba(218,191,124,0.10); backdrop-filter: blur(18px) saturate(140%); }
.sig-xianxia-hero .artifact h2 { margin: 0; font-size: 13px; color: #dabf7c; text-transform: uppercase; letter-spacing: 0; }
.sig-xianxia-hero .metric-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
.sig-xianxia-hero .metric { padding: 14px; border: 1px solid rgba(218,191,124,0.30); border-radius: calc(16px - 4px); background: color-mix(in srgb, rgba(16,29,25,0.88) 76%, transparent); }
.sig-xianxia-hero .metric strong { display: block; font-size: 30px; line-height: 1; font-variant-numeric: tabular-nums; }
.sig-xianxia-hero .metric span { display: block; margin-top: 6px; color: #b7c3aa; font-size: 11px; }
.sig-xianxia-hero .rail { height: 9px; border-radius: 999px; background: linear-gradient(90deg, #dabf7c, #8fc7aa); }
@media (max-width: 780px) { .sig-xianxia-hero { grid-template-columns: 1fr; padding: 28px; } }

.sig-xianxia-card { width: min(100%, 390px); padding: 22px; border: 1px solid rgba(218,191,124,0.30); border-radius: 16px; background: rgba(16,29,25,0.88); color: #f3ead2; box-shadow: 0 32px 82px rgba(4,8,7,0.40); font-family: Inter, "Noto Sans SC", ui-sans-serif, system-ui, sans-serif; }
.sig-xianxia-card .top { display: flex; align-items: start; justify-content: space-between; gap: 16px; margin-bottom: 24px; }
.sig-xianxia-card .label { color: #dabf7c; font-size: 12px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-xianxia-card .pill { border: 1px solid rgba(218,191,124,0.30); border-radius: 999px; padding: 5px 9px; color: #b7c3aa; background: rgba(218,191,124,0.10); font-size: 11px; }
.sig-xianxia-card h3 { margin: 0 0 10px; font-family: "Noto Serif SC", Georgia, serif; font-size: 32px; line-height: 1; letter-spacing: 0; }
.sig-xianxia-card p { margin: 0; color: #b7c3aa; font-size: 13px; line-height: 1.7; }
.sig-xianxia-card .strip { display: grid; grid-template-columns: 1fr auto; gap: 12px; margin-top: 22px; padding-top: 16px; border-top: 1px solid rgba(218,191,124,0.30); }
.sig-xianxia-card .strip strong { font-variant-numeric: tabular-nums; color: #f3ead2; }
.sig-xianxia-card .signal { width: 38px; height: 38px; display: grid; place-items: center; border-radius: calc(16px - 4px); background: #dabf7c; color: #101d19; font-weight: 900; }

.sig-xianxia-nav { width: min(100%, 900px); min-height: 74px; display: flex; align-items: center; justify-content: space-between; gap: 24px; padding: 14px 16px; border: 1px solid rgba(218,191,124,0.30); border-radius: 16px; background: rgba(16,29,25,0.88); color: #f3ead2; box-shadow: 0 32px 82px rgba(4,8,7,0.40); font-family: Inter, "Noto Sans SC", ui-sans-serif, system-ui, sans-serif; }
.sig-xianxia-nav .brand { display: flex; align-items: center; gap: 10px; min-width: max-content; font-family: "Noto Serif SC", Georgia, serif; font-size: 15px; font-weight: 800; letter-spacing: 0; }
.sig-xianxia-nav .mark { width: 30px; height: 30px; border-radius: calc(16px - 4px); background: linear-gradient(135deg, #dabf7c, #8fc7aa); box-shadow: inset 0 0 0 1px rgba(218,191,124,0.30); }
.sig-xianxia-nav .links { display: flex; align-items: center; gap: 4px; min-width: 0; overflow-x: auto; }
.sig-xianxia-nav a { height: 34px; display: inline-flex; align-items: center; padding: 0 12px; border-radius: calc(16px - 6px); color: #b7c3aa; text-decoration: none; font-size: 13px; transition: color 160ms, background 160ms; white-space: nowrap; }
.sig-xianxia-nav a:hover, .sig-xianxia-nav a.active { color: #f3ead2; background: rgba(218,191,124,0.10); }
.sig-xianxia-nav button { height: 34px; padding: 0 13px; border-radius: calc(16px - 6px); border: 1px solid #dabf7c; background: #dabf7c; color: #101d19; font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; white-space: nowrap; }
@media (max-width: 720px) { .sig-xianxia-nav { align-items: stretch; flex-direction: column; } }

.sig-xianxia-form { width: min(100%, 440px); display: grid; gap: 15px; padding: 22px; border: 1px solid rgba(218,191,124,0.30); border-radius: 16px; background: rgba(16,29,25,0.88); color: #f3ead2; box-shadow: 0 32px 82px rgba(4,8,7,0.40); font-family: Inter, "Noto Sans SC", ui-sans-serif, system-ui, sans-serif; }
.sig-xianxia-form label { display: grid; gap: 7px; font-size: 13px; font-weight: 800; color: #f3ead2; }
.sig-xianxia-form small { color: #b7c3aa; font-size: 12px; line-height: 1.55; font-weight: 400; }
.sig-xianxia-form .row { display: flex; gap: 10px; }
.sig-xianxia-form input { min-width: 0; flex: 1; height: 42px; border-radius: calc(16px - 6px); border: 1px solid rgba(218,191,124,0.30); background: rgba(218,191,124,0.10); color: #f3ead2; padding: 0 12px; font: inherit; outline: none; transition: border-color 160ms, box-shadow 160ms; }
.sig-xianxia-form input:focus { border-color: #dabf7c; box-shadow: 0 0 0 3px color-mix(in srgb, #dabf7c 18%, transparent); }
.sig-xianxia-form button { height: 42px; padding: 0 14px; border-radius: calc(16px - 6px); border: 1px solid #dabf7c; background: #dabf7c; color: #101d19; font: inherit; font-size: 13px; font-weight: 800; cursor: pointer; }
@media (max-width: 520px) { .sig-xianxia-form .row { flex-direction: column; } }

.sig-xianxia-table { width: min(100%, 780px); overflow: hidden; border: 1px solid rgba(218,191,124,0.30); border-radius: 16px; background: rgba(16,29,25,0.88); color: #f3ead2; box-shadow: 0 32px 82px rgba(4,8,7,0.40); font-family: Inter, "Noto Sans SC", ui-sans-serif, system-ui, sans-serif; }
.sig-xianxia-table table { width: 100%; border-collapse: collapse; font-size: 13px; }
.sig-xianxia-table th, .sig-xianxia-table td { padding: 12px 14px; text-align: left; border-bottom: 1px solid rgba(218,191,124,0.30); }
.sig-xianxia-table th { color: #b7c3aa; font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0; background: rgba(218,191,124,0.10); }
.sig-xianxia-table td { color: #f3ead2; }
.sig-xianxia-table tr:last-child td { border-bottom: 0; }
.sig-xianxia-table tbody tr:hover td { background: rgba(218,191,124,0.10); }
.sig-xianxia-table .mono { font-variant-numeric: tabular-nums; }
.sig-xianxia-table .status { display: inline-flex; align-items: center; gap: 6px; color: #dabf7c; font-weight: 800; }
.sig-xianxia-table .status::before { content: ""; width: 7px; height: 7px; border-radius: 50%; background: #dabf7c; }

.xian-btn-jade {
  padding: 10px 20px;
  background: rgba(126, 226, 196, 0.06);
  color: #7ee2c4;
  font-family: 'Inter', system-ui;
  font-size: 13px;
  font-weight: 500;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  border: 1px solid rgba(126, 226, 196, 0.2);
  border-radius: 6px;
  cursor: pointer;
  transition: all 0.3s cubic-bezier(0.22, 0.61, 0.36, 1);
}
.xian-btn-jade:hover {
  background: rgba(126, 226, 196, 0.1);
  border-color: rgba(126, 226, 196, 0.4);
  box-shadow: 0 0 24px rgba(126, 226, 196, 0.15);
}
.xian-btn-jade:active {
  background: rgba(126, 226, 196, 0.14);
}

.xian-btn-gold {
  padding: 9px 20px;
  background: transparent;
  color: #f5c66b;
  font-family: 'Cinzel', serif;
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  border: 1px solid rgba(245, 198, 107, 0.35);
  border-radius: 6px;
  cursor: pointer;
  transition: all 0.3s;
}
.xian-btn-gold:hover {
  border-color: rgba(245, 198, 107, 0.6);
  box-shadow: 0 0 16px rgba(245, 198, 107, 0.15);
}

.xian-btn-void {
  padding: 8px 16px;
  background: transparent;
  color: rgba(203, 213, 245, 0.7);
  font-family: 'Inter', system-ui;
  font-size: 13px;
  border: 1px solid rgba(203, 213, 245, 0.08);
  border-radius: 6px;
  cursor: pointer;
  transition: all 0.2s;
}
.xian-btn-void:hover {
  color: #cbd5f5;
  border-color: rgba(203, 213, 245, 0.18);
  background: rgba(255, 255, 255, 0.02);
}

.xian-bg-xuan {
  min-height: 100vh;
  background-color: #03060d;
  background-image:
    radial-gradient(900px 600px at 12% -8%, rgba(245, 198, 107, 0.05), transparent 60%),
    radial-gradient(1100px 700px at 110% 20%, rgba(126, 226, 196, 0.045), transparent 65%),
    radial-gradient(700px 500px at 50% 120%, rgba(232, 85, 109, 0.035), transparent 70%),
    url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='180' height='180'><filter id='n'><feTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='2' stitchTiles='stitch'/><feColorMatrix values='0 0 0 0 0.55  0 0 0 0 0.6  0 0 0 0 0.7  0 0 0 0.06 0'/></filter><rect width='100%25' height='100%25' filter='url(%23n)'/></svg>");
  background-attachment: fixed;
  background-size: auto, auto, auto, 180px 180px;
}

.xian-bg-ink {
  background: linear-gradient(180deg, #0a1020 0%, #0d1424 100%);
}

.xian-card {
  padding: 24px;
  background: linear-gradient(180deg, #0a1020 0%, #0d1424 100%);
  border: 1px solid rgba(203, 213, 245, 0.10);
  border-radius: 14px;
  color: #cbd5f5;
  position: relative;
}

.xian-card-seal {
  padding: 24px;
  background: linear-gradient(180deg, rgba(245,198,107,0.04) 0%, rgba(245,198,107,0) 100%), linear-gradient(180deg, #0a1020, #0d1424);
  border: 1px solid rgba(203, 213, 245, 0.10);
  border-radius: 10px;
  color: #cbd5f5;
  position: relative;
}
.xian-card-seal::before,
.xian-card-seal::after {
  content: '';
  position: absolute;
  width: 14px;
  height: 14px;
  border-color: rgba(245, 198, 107, 0.32);
  border-style: solid;
}
.xian-card-seal::before { top: -1px; left: -1px; border-width: 1px 0 0 1px; }
.xian-card-seal::after { bottom: -1px; right: -1px; border-width: 0 1px 1px 0; }

.xian-metric {
  padding: 18px 20px;
  background: linear-gradient(180deg, #0a1020, #0d1424);
  border: 1px solid rgba(203, 213, 245, 0.10);
  border-radius: 10px;
}
.xian-metric .label {
  font-family: 'JetBrains Mono', monospace;
  font-size: 10px;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: rgba(203, 213, 245, 0.5);
  margin-bottom: 6px;
}
.xian-metric .value {
  font-family: 'Inter', system-ui;
  font-size: 28px;
  font-weight: 700;
  color: #cbd5f5;
  font-variant-numeric: tabular-nums;
}
.xian-metric .status {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-top: 6px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  color: #7ee2c4;
}
.xian-metric .status .dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: #7ee2c4;
  box-shadow: 0 0 8px #7ee2c4;
}

.xian-sidebar {
  width: 224px;
  display: flex;
  flex-direction: column;
  background: rgba(10, 16, 32, 0.3);
  backdrop-filter: blur(4px);
  border-right: 1px solid rgba(203, 213, 245, 0.10);
  height: 100vh;
}
.xian-sidebar .logo {
  padding: 28px 20px 16px;
}
.xian-sidebar .logo .name {
  font-family: 'Cinzel', serif;
  font-size: 18px;
  letter-spacing: 0.22em;
  color: #f5c66b;
}
.xian-sidebar .logo .sub {
  font-family: 'JetBrains Mono', monospace;
  font-size: 10px;
  letter-spacing: 0.32em;
  text-transform: uppercase;
  color: rgba(203, 213, 245, 0.5);
}
.xian-sidebar .gold-line {
  height: 1px;
  margin: 0 20px;
  background: linear-gradient(90deg, transparent, rgba(245,198,107,0.4), transparent);
}
.xian-sidebar nav {
  padding: 16px 12px;
  display: flex;
  flex-direction: column;
  gap: 2px;
}
.xian-sidebar nav a {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 12px;
  border-radius: 6px;
  font-family: 'Cinzel', serif;
  font-size: 13px;
  letter-spacing: 0.18em;
  color: rgba(203, 213, 245, 0.65);
  text-decoration: none;
  position: relative;
  transition: all 0.2s;
}
.xian-sidebar nav a:hover {
  color: #cbd5f5;
  background: rgba(255, 255, 255, 0.02);
}
.xian-sidebar nav a.active {
  color: #f5c66b;
  background: #0d1424;
}
.xian-sidebar nav a.active::before {
  content: '';
  position: absolute;
  left: 0;
  top: 8px;
  bottom: 8px;
  width: 2px;
  border-radius: 1px;
  background: #f5c66b;
  box-shadow: 0 0 8px #f5c66b;
}

.xian-badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 2px 10px;
  border-radius: 999px;
  border: 1px solid rgba(203,213,245,0.1);
  background: rgba(255,255,255,0.02);
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}
.xian-badge .dot { width: 6px; height: 6px; border-radius: 999px; }
.xian-badge[data-tone='yu'] { color: #7ee2c4; border-color: rgba(126,226,196,0.35); }
.xian-badge[data-tone='yu'] .dot { background: #7ee2c4; box-shadow: 0 0 8px #7ee2c4; }
.xian-badge[data-tone='jin'] { color: #f5c66b; border-color: rgba(245,198,107,0.45); }
.xian-badge[data-tone='jin'] .dot { background: #f5c66b; box-shadow: 0 0 8px #f5c66b; }
.xian-badge[data-tone='zhu'] { color: #e8556d; border-color: rgba(232,85,109,0.40); }
.xian-badge[data-tone='zhu'] .dot { background: #e8556d; box-shadow: 0 0 8px #e8556d; }

.xian-gold-line {
  height: 1px;
  background: linear-gradient(
    90deg,
    transparent 0%,
    rgba(245, 198, 107, 0) 6%,
    rgba(245, 198, 107, 0.55) 50%,
    rgba(245, 198, 107, 0) 94%,
    transparent 100%
  );
}

.xian-pulse-yu {
  animation: xian-yupulse 2.4s cubic-bezier(0.22, 0.61, 0.36, 1) infinite;
}
@keyframes xian-yupulse {
  0%, 100% { box-shadow: 0 0 0 1px #7ee2c4 inset, 0 0 0 0 rgba(126,226,196,0); }
  50% { box-shadow: 0 0 0 1px #7ee2c4 inset, 0 0 24px 2px rgba(126,226,196,0.45); }
}

.xian-input {
  width: 100%;
  padding: 10px 14px;
  background: #0a1020;
  border: 1px solid rgba(203, 213, 245, 0.10);
  border-radius: 6px;
  color: #cbd5f5;
  font-family: 'Inter', system-ui;
  font-size: 14px;
  outline: none;
  transition: border-color 0.2s, box-shadow 0.2s;
}
.xian-input:focus {
  border-color: rgba(126, 226, 196, 0.4);
  box-shadow: 0 0 12px rgba(126, 226, 196, 0.08);
}
.xian-input::placeholder { color: rgba(203, 213, 245, 0.3); }

.xian-table {
  width: 100%;
  border-collapse: collapse;
  font-family: 'Inter', system-ui;
}
.xian-table th {
  padding: 8px 14px;
  text-align: left;
  font-family: 'JetBrains Mono', monospace;
  font-size: 10px;
  font-weight: 500;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: rgba(203, 213, 245, 0.4);
  border-bottom: 1px solid rgba(203, 213, 245, 0.08);
}
.xian-table td {
  padding: 10px 14px;
  font-size: 13px;
  color: #cbd5f5;
  border-bottom: 1px solid rgba(203, 213, 245, 0.05);
}
.xian-table tr:hover td { background: rgba(255, 255, 255, 0.015); }
.xian-table tr:last-child td { border-bottom: none; }

.xian-modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(3, 6, 13, 0.75);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 9999;
}
.xian-modal {
  width: min(90%, 420px);
  padding: 28px;
  background: linear-gradient(180deg, #0a1020, #0d1424);
  border: 1px solid rgba(203, 213, 245, 0.10);
  border-radius: 10px;
  position: relative;
}
.xian-modal::before, .xian-modal::after {
  content: '';
  position: absolute;
  width: 12px;
  height: 12px;
  border-color: rgba(245, 198, 107, 0.3);
  border-style: solid;
}
.xian-modal::before { top: -1px; left: -1px; border-width: 1px 0 0 1px; }
.xian-modal::after { bottom: -1px; right: -1px; border-width: 0 1px 1px 0; }
.xian-modal h3 {
  font-family: 'Cinzel', serif;
  font-size: 16px;
  letter-spacing: 0.12em;
  color: #f5c66b;
  margin: 0 0 10px;
}
.xian-modal p {
  font-family: 'Inter', system-ui;
  font-size: 14px;
  color: rgba(203, 213, 245, 0.7);
  line-height: 1.6;
  margin: 0 0 20px;
}
.xian-modal .actions { display: flex; justify-content: flex-end; gap: 10px; }

.xian-footer {
  padding: 16px 20px;
}
.xian-footer .gold-line {
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(245,198,107,0.35), transparent);
  margin-bottom: 12px;
}
.xian-footer .text {
  font-family: 'JetBrains Mono', monospace;
  font-size: 10px;
  letter-spacing: 0.28em;
  text-transform: uppercase;
  color: rgba(203, 213, 245, 0.45);
}

.xian-layout {
  display: grid;
  grid-template-columns: 224px 1fr;
  height: 100vh;
  background: #03060d;
  color: #cbd5f5;
}
.xian-layout .sidebar {
  border-right: 1px solid rgba(203, 213, 245, 0.08);
  background: rgba(10, 16, 32, 0.3);
  backdrop-filter: blur(4px);
}
.xian-layout .content {
  padding: 32px;
  overflow-y: auto;
}

.xian-hero {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  padding: 40px;
  background: #03060d;
}
.xian-hero h1 {
  font-family: 'Cinzel', serif;
  font-size: clamp(48px, 10vw, 80px);
  font-weight: 400;
  letter-spacing: 0.08em;
  color: #f5c66b;
  margin: 0 0 20px;
  text-shadow: 0 0 40px rgba(245, 198, 107, 0.2);
}
.xian-hero p {
  font-family: 'Inter', system-ui;
  font-size: 15px;
  color: rgba(203, 213, 245, 0.6);
  max-width: 480px;
  line-height: 1.7;
  margin: 0;
}

.xian-rise {
